head.script:
console.log('========================op_304_01_37b=====================');

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

};

scwin.onUdcCompleted = function () { // scwin.f_dsOrderSearchHeader(); // 오더요청현황 조회조건

    ed_srchWrkStDt.setValue(WebSquare.date.dateAdd(WebSquare.date.getCurrentServerDate("yyyyMMdd"), -7));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));

    var memJson = $c.data.getMemInfo();

    scwin.vehclNo           = $c.data.getParameter('vehclNo');
    scwin.logisticsBranch   = $c.data.getParameter('logisticsBranch');
    scwin.rsltsStdDt        = $c.data.getParameter('rsltsStdDt');
    scwin.rsltsEndDt        = $c.data.getParameter('rsltsEndDt');
    scwin.pchsClntNo        = $c.data.getParameter('pchsClntNo');
    scwin.transCargoClsCd   = $c.data.getParameter('transCargoClsCd');

    // 공통코드
    const codeOptions = [
        { grpCd: "OP190", compID: "co_lc_srchWrkClsCd" }
    ];
    $c.data.setCommonCode(codeOptions, async function() {

        if (memJson.loUpperLobranCd) {
            co_lc_logisticsBranch.setValue(memJson.loUpperLobranCd);
        } else {
            co_lc_logisticsBranch.setSelectedIndex(0);
        }
        co_lc_srchWrkClsCd.setSelectedIndex(1);

        if (scwin.vehclNo) {
            co_lc_logisticsBranch.setValue(scwin.logisticsBranch);    // 지점배차점소
            ed_srchWrkStDt.setValue(scwin.rsltsStdDt ? scwin.rsltsStdDt : '');                     // from
            ed_srchWrkEndDt.setValue(scwin.rsltsEndDt ? scwin.rsltsEndDt : '');                    // to
            co_lc_srchWrkClsCd.setValue(scwin.transCargoClsCd ? scwin.transCargoClsCd : '');       // 작업구분
            ed_clntNo.setValue(scwin.pchsClntNo ? scwin.pchsClntNo : '');                          // 계약거래처
            ed_srchVehclNo.setValue(scwin.vehclNo ? scwin.vehclNo : '');                           // 차량번호

            $c.sbm.execute(sbm_Retrieve);
        }
    });

    scwin.initComp();
}

scwin.initComp = function() {

    var codeObj = [ed_clntNo];

    for (var i = 0 ; i < codeObj.length ; i ++) {
        codeObj[i].unbind('onkeyup');

        codeObj[i].bind('onkeyup', function() {
            var oldVal = this._oldValue;
            this.setValue(this.getValue().toUpperCase());

            this._oldValue = oldVal;
        })
    }
}


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {

    if (ed_srchWrkStDt.getValue() == "" || ed_srchWrkEndDt.getValue() == "") {
        await $c.win.alert("필수입력사항을 입력해주세요.");
        return;
    }

    if (co_lc_logisticsBranch.getValue() == "" && ed_srchVehclNo.getValue() == "") {
        await $c.win.alert("전체로 조회시에는 차량번호는 필수입력사항입니다.");
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};

scwin.f_FieldClear = function () {

    ed_srchWrkStDt.setValue(WebSquare.date.dateAdd(WebSquare.date.getCurrentServerDate("yyyyMMdd"), -7));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));

    ed_clntNo.setValue("");
    ed_clntNm.setValue("");
    ed_copCoClntNo.setValue("");
    ed_copCoClntNm.setValue("");
    ed_srchEqCd.setValue("");
    ed_srchVehclNo.setValue("");
    co_lc_logisticsBranch.setSelectedIndex(0);
    co_lc_srchWrkClsCd.setSelectedIndex(0);
}


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (type, disGubun, codeObj, nameObj, pClose, pAllSearch) {

    var codeVal = (codeObj) ? codeObj.getValue() : '';
    var nameVal = (nameObj) ? nameObj.getValue() : '';

    if (codeObj) codeObj.setValue('');
    if (nameObj) nameObj.setValue('');

    if (type == 'CODE') {
        if (codeVal == '') return;
    } else if (type == 'NAME') {
        if (nameVal == '') return;
    }

    if (type == 'CODE') {  
        scwin.f_openCommonPopUp(disGubun, codeVal, '', pClose, pAllSearch);
    } else if (type == 'NAME') {
        scwin.f_openCommonPopUp(disGubun, '', nameVal, pClose, pAllSearch);
    } else {
        scwin.f_openCommonPopUp(disGubun, codeVal, nameVal, pClose, pAllSearch);
    }
}

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1: // 거래처 팝업
            udc_clntNo.setSelectId("retrieveClntInfo2"); // XML상의 SELECT ID
            udc_clntNo.cfCommonPopUp(function(ret) {
                    $c.gus.cfSetReturnValue(ret, ed_clntNo, ed_clntNm);
                }  // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "계약 거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 4: // 차량번호 팝업	
            udc_srchEqCd.setSelectId("retrieveVehiclesNo"); // XML상의 SELECT ID
            udc_srchEqCd.cfCommonPopUp(function(ret) {
                    $c.gus.cfSetReturnValue(ret, ed_srchEqCd, ed_srchVehclNo);
                }  // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , "F" // 전체검색허용여부 ("F")
                , "차량번호,차량번호코드,차량번호명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 5: // 협력업체 팝업	
            udc_copCoClntNo.setSelectId("retrieveClntList"); // XML상의 SELECT ID
            udc_copCoClntNo.cfCommonPopUp(function(ret) {
                    $c.gus.cfSetReturnValue(ret, ed_copCoClntNo, ed_copCoClntNm);
                }  // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 원도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
}

scwin.f_gridSumTextDisplay = function () {

    ds_oderCondition_sum.removeAll();
    ds_oderCondition_sum.setJSON(ds_oderCondition.getAllJSON());

    var clntNm = '';
    var sellAmt = 0, pchsAmt = 0, wrkQty = 0, wrkWt = 0, wrkCubic = 0;
    var totalProfit = 0, totSellAmt = 0, totPchsAmt = 0, totWrkQty = 0, totWrkWt = 0, totWrkCubic = 0;
    var chkVal = ds_oderCondition_sum.getCellData(0, "clntNm"); 
    var sumData = [];

    if (ds_oderCondition_sum.getRowCount() != 0) {

        for (var i = 0; i < ds_oderCondition_sum.getRowCount(); i++) {

            clntNm      = ds_oderCondition_sum.getCellData(i, "clntNm");

            if (i != 0 && chkVal != clntNm) {
                totalProfit = (sellAmt == 0) ? 0 : Math.trunc((pchsAmt / sellAmt) * 100 * 1000) / 1000;

                sumData.push({
                    clntNm      : (chb_subtotal.getValue() == '1') ? chkVal : '소 계',
                    wrkQty      : wrkQty,
                    wrkWt       : wrkWt,
                    wrkCubic    : wrkCubic,
                    pchsAmt     : pchsAmt,
                    sellAmt     : sellAmt,
                    totalProfit : (totalProfit == 0) ? '' : totalProfit,
                    isSum       : true,
                    idx         : i
                });

                chkVal      = clntNm;
                wrkQty      = 0;
                wrkWt       = 0;
                wrkCubic    = 0;
                pchsAmt     = 0;
                sellAmt     = 0;
                totalProfit = 0;
            }

            wrkQty          += Number(ds_oderCondition_sum.getCellData(i, "wrkQty"));
            wrkWt           += Number(ds_oderCondition_sum.getCellData(i, "wrkWt"));
            wrkCubic        += Number(ds_oderCondition_sum.getCellData(i, "wrkCubic"));
            pchsAmt         += Number(ds_oderCondition_sum.getCellData(i, "pchsAmt"));
            sellAmt         += Number(ds_oderCondition_sum.getCellData(i, "sellAmt"));
            totWrkQty       += Number(ds_oderCondition_sum.getCellData(i, "wrkQty"));
            totWrkWt        += Number(ds_oderCondition_sum.getCellData(i, "wrkWt"));
            totWrkCubic     += Number(ds_oderCondition_sum.getCellData(i, "wrkCubic"));
            totSellAmt      += Number(ds_oderCondition_sum.getCellData(i, "sellAmt"));
            totPchsAmt      += Number(ds_oderCondition_sum.getCellData(i, "pchsAmt"));
        }

        totalProfit = (sellAmt == 0) ? 0 : Math.trunc((pchsAmt / sellAmt) * 100 * 1000) / 1000;
        sumData.push({
            clntNm      : (chb_subtotal.getValue() == '1') ? chkVal : '소 계',
            wrkQty      : wrkQty,
            wrkWt       : wrkWt,
            wrkCubic    : wrkCubic,
            pchsAmt     : pchsAmt,
            sellAmt     : sellAmt,
            totalProfit : (totalProfit == 0) ? '' : totalProfit,
            isSum       : true,
            idx         : ds_oderCondition.getRowCount()
        });

        // 소계 스타일 적용
        if (chb_subtotal.getValue() == '1') {
            ds_oderCondition_sum.removeAll();
            ds_oderCondition_sum.setJSON(sumData);
        } else {

            for (var i = sumData.length -1 ; i > -1 ; i --) {
                var idx = sumData[i].idx;

                ds_oderCondition_sum.insertJSON(idx, [sumData[i]]);

                for (var j = 0 ; j < gr_oderCondition.getColumnCount() ; j ++) {
                    if (j == 0) {
                        gr_oderCondition.setCellClass(idx, j, 'gridSubtotalDefault excelSubtotalLeft');
                    } else {
                        gr_oderCondition.setCellClass(idx, j, 'gridSubtotalDefault excelSubtotalRight');
                    }
                }
            }
        }
    }

    // 전체 합계 (totalProfit);
    totalProfit = (totSellAmt == 0) ? 0 : Math.trunc((totPchsAmt / totSellAmt) * 100 * 1000) / 1000;
    gr_oderCondition.setFooterValue("f_selfVehclNo", ds_oderCondition.getRowCount());
    gr_oderCondition.setFooterValue("f_wrkQty", totWrkQty);
    gr_oderCondition.setFooterValue("f_wrkWt", totWrkWt);
    gr_oderCondition.setFooterValue("f_wrkCubic", totWrkCubic);
    gr_oderCondition.setFooterValue("f_pchsAmt", totPchsAmt);
    gr_oderCondition.setFooterValue("f_sellAmt", totSellAmt);
    gr_oderCondition.setFooterValue("f_totalProfit", (totalProfit == 0) ? '' : totalProfit);

};

scwin.excel = async function () {

    var totCnt = ds_oderCondition_sum.getRowCount();
    var sheetTitle = "차량별운송실적조회";

    if (totCnt != 0) {
        cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_oderCondition, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle });
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
}




//-------------------------------------------------------------------------
// Data Collection Event
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {

    ed_totalCnt.setValue(ds_oderCondition.getRowCount());

    if (ds_oderCondition.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003, new Array("조회결과"));
    } else {
        for (var i = 0 ; i < ds_oderCondition.getRowCount(); i++) {
            ds_oderCondition.setCellData(i, 'dptDt', ds_oderCondition.getCellData(i, 'dptDt').substring(0, 8));
            ds_oderCondition.setCellData(i, 'sort', i);
        }
    }
    scwin.f_gridSumTextDisplay();
};



//-----------------------------------------------------------------------
// Common Code Event
//-----------------------------------------------------------------------
// 계약거래처
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_chkOpenCommonPopUp("SEARCH", 1, ed_clntNo, ed_clntNm, 'T', 'T');
};
scwin.udc_clntNo_onviewchangeCodeEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("CODE", 1, ed_clntNo, ed_clntNm, 'T', 'T');
};
scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("NAME", 1, ed_clntNo, ed_clntNm, 'T', 'T');
};


// 협력업체
scwin.udc_copCoClntNo_onclickEvent = function (e) {
    scwin.f_chkOpenCommonPopUp("SEARCH", 5, ed_copCoClntNo, ed_copCoClntNm, "F", "F");
};
scwin.udc_copCoClntNo_onviewchangeCodeEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("CODE", 5, ed_copCoClntNo, ed_copCoClntNm, "T", "T");
};
scwin.udc_copCoClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("NAME", 5, ed_copCoClntNo, ed_copCoClntNm, "T", "T");
};


// 차량번호
scwin.udc_srchEqCd_onclickEvent = function (e) {
    scwin.f_chkOpenCommonPopUp("SEARCH", 4, ed_srchEqCd, ed_srchVehclNo, "F", "F");
};
scwin.udc_srchEqCd_onviewchangeCodeEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("CODE", 4, ed_srchEqCd, ed_srchVehclNo, "T", "T");
};
scwin.udc_srchEqCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp("NAME", 4, ed_srchEqCd, ed_srchVehclNo, "T", "T");
};



//-------------------------------------------------------------------------
// Component Event
//-------------------------------------------------------------------------
scwin.co_lc_srchWrkClsCd_onchange = function (info) {

    if (co_lc_srchWrkClsCd.getValue() == "C") {
        gr_oderCondition.setColumnVisible("wrkQty", false);
        gr_oderCondition.setColumnVisible("wrkWt", false);
        gr_oderCondition.setColumnVisible("wrkCubic", false);
        gr_oderCondition.setColumnVisible("cntrSizCd", true);
        gr_oderCondition.setColumnVisible("cntrTypCd", true);
        gr_oderCondition.setColumnVisible("fullEmptyClsCd", true);
        gr_oderCondition.setColumnVisible("cntrNo", true);
        gr_oderCondition.setColumnVisible("sellAmt", false);
        gr_oderCondition.setColumnVisible("totalProfit", false);

        // [ADD] profitRate도 B 전용이면 숨김
        //gr_oderCondition.setColumnVisible("profitRate", false);

    } else if (co_lc_srchWrkClsCd.getValue() == "B") {
        gr_oderCondition.setColumnVisible("wrkQty", true);
        gr_oderCondition.setColumnVisible("wrkWt", true);
        gr_oderCondition.setColumnVisible("wrkCubic", true);
        gr_oderCondition.setColumnVisible("cntrSizCd", false);
        gr_oderCondition.setColumnVisible("cntrTypCd", false);
        gr_oderCondition.setColumnVisible("fullEmptyClsCd", false);
        gr_oderCondition.setColumnVisible("cntrNo", false);
        gr_oderCondition.setColumnVisible("sellAmt", true);
        gr_oderCondition.setColumnVisible("totalProfit", true);

        // [ADD] B일 때 profitRate 노출
        //gr_oderCondition.setColumnVisible("profitRate", true);

    } else {
        gr_oderCondition.setColumnVisible("wrkQty", true);
        gr_oderCondition.setColumnVisible("wrkWt", true);
        gr_oderCondition.setColumnVisible("wrkCubic", true);
        gr_oderCondition.setColumnVisible("cntrSizCd", true);
        gr_oderCondition.setColumnVisible("cntrTypCd", true);
        gr_oderCondition.setColumnVisible("fullEmptyClsCd", true);
        gr_oderCondition.setColumnVisible("cntrNo", true);
        gr_oderCondition.setColumnVisible("sellAmt", true);
        gr_oderCondition.setColumnVisible("totalProfit", true);

        // [ADD] 기본은 보이게(필요 시 숨김)
        //gr_oderCondition.setColumnVisible("profitRate", true);
    }
};


scwin.gr_oderCondition_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == "odrNo") {
        // 오더세부사항 조회 
        scwin.f_orderDetail(rowIndex);
    }
};

scwin.gr_oderCondition_onbeforesort = function (sortInfo) {

    console.log(sortInfo);

    for (var i = ds_oderCondition_sum.getRowCount() -1 ; i  > -1  ; i --) {
        if (ds_oderCondition_sum.getCellData(i, "isSum") == true) {
            ds_oderCondition_sum.removeRow(i);
        }
    }
    ds_oderCondition._sortInfo = sortInfo;
};

//-------------------------------------------------------------------------
// 오더 상세 화면 이동 
//-------------------------------------------------------------------------
scwin.f_orderDetail = async function (rowIndex) {

    if (rowIndex != -1) {
        if (ds_oderCondition_sum.getCellData(rowIndex, "appCarSize") == "B") {
            scwin.f_bulkOrderDetail(rowIndex);
        } else {
            scwin.f_containerOrderDetail(rowIndex);
        }

    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더현황"]); 
	    return;
    }
}

//-------------------------------------------------------------------------
// 벌크 오더 
//-------------------------------------------------------------------------	
scwin.f_bulkOrderDetail = async function (rowIndex) {

    $c.win.openMenu(
        "벌크오더",
        "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml",
        "sd_402_01_02t.xml",
        {
            odrNo   : ds_oderCondition_sum.getCellData(rowIndex, "odrNo"),
            type    : 'retrieve'
        },
        {openAction: "exist"}
    );
}


scwin.f_containerOrderDetail = async function (rowIndex) {

    $c.win.openMenu(
        "컨테이너오더",
        "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml",
        "sd_402_01_11t.xml",
        {
            odrNo   : ds_oderCondition_sum.getCellData(rowIndex, "odrNo"),
            type    : 'retrieve'
        },
        {openAction: "exist"}
    );
}


scwin.setFormatter = function (d) {
    if (d == 0) return "";
    return Number(d).toLocaleString();
}

scwin.setFormatter1 = function (d) {
    if (d == 0) return "";
    return Number(d).toLocaleString();
}

scwin.setFormatter2 = function (d) {
    if (d == 0) return "";
    return Number(d).toLocaleString();
}
